{
  "summary": "The paper presents CORA, a unified multilingual open question answering system that integrates cross-lingual dense passage retrieval with multilingual answer generation. It employs an iterative training procedure with automatic cross-lingual data expansion using Wikipedia language links, achieving state-of-the-art results on large-scale multilingual QA benchmarks, particularly benefiting low-resource and unseen languages.",
  "strengths": [
    {
      "point": "Unified multilingual QA model without reliance on external translation or language-specific components",
      "evidence": "CORA directly retrieves passages across multiple languages and generates answers in the target language using mDPR and mGEN models."
    },
    {
      "point": "Iterative training with cross-lingual data expansion improves performance on low-resource and unseen languages",
      "evidence": "The method uses Wikipedia language links and model predictions to expand training data without human annotation or machine translation."
    },
    {
      "point": "Strong empirical results demonstrating significant improvements over prior state-of-the-art on diverse multilingual QA benchmarks",
      "evidence": "CORA achieves +21.4 F1 on XOR-TYDI QA and +4.9 F1 on MKQA, including +5.4 F1 on 9 unseen languages."
    },
    {
      "point": "Comprehensive analysis of cross-lingual retrieval impact and human evaluation confirming relevance of retrieved passages",
      "evidence": "Human evaluation shows high relevance of cross-lingual retrieved passages; analysis highlights retrieval from multiple languages as important."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent strong multilingual dense retrieval baselines",
      "evidence": "No experiments or discussion comparing mDPR to models like mContriever or LaBSE-based retrievers."
    },
    {
      "point": "Insufficient justification and ablation for choice of mBERT as retrieval encoder backbone",
      "evidence": "No ablation comparing mBERT to stronger multilingual encoders such as XLM-R or mDeBERTa."
    },
    {
      "point": "Missing detailed description and quantitative analysis of cross-lingual data expansion filtering and noise handling",
      "evidence": "No heuristics, thresholds, or noise impact analysis provided for Wikipedia language link mining."
    },
    {
      "point": "Incomplete evaluation lacking supervised MKQA baselines and complementary answer quality metrics",
      "evidence": "Zero-shot MKQA results are not contextualized with fully supervised baselines; only F1 scores reported without metrics like EM or human evaluation of answer quality."
    },
    {
      "point": "Reproducibility concerns due to missing critical training hyperparameters and retrieval index construction details",
      "evidence": "Key hyperparameters, passage segmentation, indexing infrastructure, and retrieval setup are not described."
    },
    {
      "point": "Clarity issues regarding definition of 'unseen languages' and input formatting for answer generation",
      "evidence": "Unclear which languages are unseen and how mGEN conditions on multiple retrieved passages."
    },
    {
      "point": "Limited discussion of limitations including scalability, Wikipedia bias, and mitigation strategies for generation language mismatches",
      "evidence": "No analysis of computational costs, Wikipedia coverage bias, or proposed solutions for language mismatches in generation."
    }
  ],
  "questions": [
    {
      "question": "How does CORA’s retrieval component compare empirically to recent state-of-the-art multilingual dense retrievers like mContriever or LaBSE-based models?",
      "motivation": "Understanding this is critical to assess the novelty and effectiveness of the retrieval architecture beyond data and training improvements."
    },
    {
      "question": "What are the effects of varying the number and length of retrieved passages on answer generation quality and efficiency?",
      "motivation": "This impacts practical deployment and tuning of the system for different resource constraints and use cases."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
